import os
import json
import pymysql
from google.cloud import secretmanager


def get_db_password():
    """Retrieve database password from Secret Manager."""
    client = secretmanager.SecretManagerServiceClient()
    project_id = os.environ.get("GCP_PROJECT")
    secret_name = os.environ.get("DB_PASSWORD_SECRET", "cloud-sql-password")
    name = f"projects/{project_id}/secrets/{secret_name}/versions/latest"
    response = client.access_secret_version(request={"name": name})
    return response.payload.data.decode("UTF-8")


def get_connection():
    """Create a database connection to Cloud SQL."""
    db_user = os.environ.get("DB_USER", "app_user")
    db_name = os.environ.get("DB_NAME", "search_db")
    db_host = os.environ.get("DB_HOST", "127.0.0.1")
    db_port = int(os.environ.get("DB_PORT", "3306"))
    db_password = get_db_password()

    connection = pymysql.connect(
        host=db_host,
        user=db_user,
        password=db_password,
        database=db_name,
        port=db_port,
        charset="utf8mb4",
        cursorclass=pymysql.cursors.DictCursor,
        connect_timeout=10,
        read_timeout=30,
    )
    return connection


# Allowlist of tables and columns that can be queried
ALLOWED_TABLES = {
    "products": {
        "columns": {"id", "name", "description", "category", "price", "status", "created_at", "updated_at"},
        "searchable": {"name", "description", "category", "status"},
        "sortable": {"id", "name", "price", "created_at", "updated_at"},
    },
    "customers": {
        "columns": {"id", "first_name", "last_name", "email", "city", "state", "country", "created_at"},
        "searchable": {"first_name", "last_name", "email", "city", "state", "country"},
        "sortable": {"id", "first_name", "last_name", "email", "created_at"},
    },
    "orders": {
        "columns": {"id", "customer_id", "status", "total_amount", "order_date", "created_at"},
        "searchable": {"status", "customer_id"},
        "sortable": {"id", "total_amount", "order_date", "created_at"},
    },
}

ALLOWED_OPERATORS = {
    "eq": "=",
    "neq": "!=",
    "gt": ">",
    "gte": ">=",
    "lt": "<",
    "lte": "<=",
    "like": "LIKE",
    "in": "IN",
}

MAX_LIMIT = 500
DEFAULT_LIMIT = 50


def validate_table(table_name):
    """Validate that the table name is in the allowlist."""
    if table_name not in ALLOWED_TABLES:
        raise ValueError(f"Invalid table: '{table_name}'. Allowed tables: {list(ALLOWED_TABLES.keys())}")
    return table_name


def validate_column(table_name, column_name, column_set="searchable"):
    """Validate that a column is allowed for the given table and operation."""
    allowed = ALLOWED_TABLES[table_name].get(column_set, set())
    if column_name not in allowed:
        raise ValueError(
            f"Column '{column_name}' is not {column_set} on table '{table_name}'. "
            f"Allowed: {sorted(allowed)}"
        )
    return column_name


def validate_operator(operator):
    """Validate that the operator is allowed."""
    if operator not in ALLOWED_OPERATORS:
        raise ValueError(f"Invalid operator: '{operator}'. Allowed: {list(ALLOWED_OPERATORS.keys())}")
    return ALLOWED_OPERATORS[operator]


def build_dynamic_query(table, filters=None, fields=None, sort_by=None, sort_order="ASC", limit=DEFAULT_LIMIT, offset=0):
    """
    Build a dynamic SQL query using parameterized queries (NOT string concatenation).
    
    This is secure against SQL injection because:
    1. Table and column names are validated against an allowlist
    2. All user-provided VALUES are passed as parameters (never concatenated)
    3. Operators are validated against an allowlist
    """
    # Validate table
    validate_table(table)

    # Build SELECT clause with validated column names
    if fields:
        validated_fields = []
        for field in fields:
            if field in ALLOWED_TABLES[table]["columns"]:
                validated_fields.append(f"`{field}`")
            else:
                raise ValueError(
                    f"Field '{field}' not available on table '{table}'. "
                    f"Available: {sorted(ALLOWED_TABLES[table]['columns'])}"
                )
        select_clause = ", ".join(validated_fields)
    else:
        select_clause = "*"

    # Start building query - table name is from allowlist, so safe to include directly
    query = f"SELECT {select_clause} FROM `{table}`"
    params = []

    # Build WHERE clause
    if filters:
        where_conditions = []
        for filter_item in filters:
            column = filter_item.get("column")
            operator_key = filter_item.get("operator", "eq")
            value = filter_item.get("value")

            # Validate column and operator against allowlists
            validate_column(table, column, "searchable")
            sql_operator = validate_operator(operator_key)

            if operator_key == "like":
                # For LIKE, wrap value with wildcards and use parameter
                where_conditions.append(f"`{column}` {sql_operator} %s")
                params.append(f"%{value}%")
            elif operator_key == "in":
                # For IN, create proper parameterized placeholders
                if not isinstance(value, list):
                    raise ValueError(f"'in' operator requires a list value, got {type(value).__name__}")
                if len(value) == 0:
                    raise ValueError("'in' operator requires a non-empty list")
                placeholders = ", ".join(["%s"] * len(value))
                where_conditions.append(f"`{column}` IN ({placeholders})")
                params.extend(value)
            else:
                where_conditions.append(f"`{column}` {sql_operator} %s")
                params.append(value)

        if where_conditions:
            query += " WHERE " + " AND ".join(where_conditions)

    # Build ORDER BY clause with validated column name
    if sort_by:
        validate_column(table, sort_by, "sortable")
        # sort_order is validated below, not user-provided raw string
        validated_sort_order = "DESC" if sort_order.upper() == "DESC" else "ASC"
        query += f" ORDER BY `{sort_by}` {validated_sort_order}"

    # Add LIMIT and OFFSET with parameterized values
    validated_limit = min(int(limit), MAX_LIMIT)
    validated_offset = max(int(offset), 0)
    query += " LIMIT %s OFFSET %s"
    params.extend([validated_limit, validated_offset])

    return query, params


def build_count_query(table, filters=None):
    """Build a COUNT query for pagination metadata."""
    validate_table(table)
    query = f"SELECT COUNT(*) as total FROM `{table}`"
    params = []

    if filters:
        where_conditions = []
        for filter_item in filters:
            column = filter_item.get("column")
            operator_key = filter_item.get("operator", "eq")
            value = filter_item.get("value")

            validate_column(table, column, "searchable")
            sql_operator = validate_operator(operator_key)

            if operator_key == "like":
                where_conditions.append(f"`{column}` {sql_operator} %s")
                params.append(f"%{value}%")
            elif operator_key == "in":
                if not isinstance(value, list) or len(value) == 0:
                    raise ValueError("'in' operator requires a non-empty list")
                placeholders = ", ".join(["%s"] * len(value))
                where_conditions.append(f"`{column}` IN ({placeholders})")
                params.extend(value)
            else:
                where_conditions.append(f"`{column}` {sql_operator} %s")
                params.append(value)

        if where_conditions:
            query += " WHERE " + " AND ".join(where_conditions)

    return query, params


def search_api(request):
    """
    HTTP Cloud Function for flexible search API.
    
    Example request body:
    {
        "table": "products",
        "fields": ["id", "name", "price", "category"],
        "filters": [
            {"column": "category", "operator": "eq", "value": "electronics"},
            {"column": "price", "operator": "lte", "value": 999.99},
            {"column": "name", "operator": "like", "value": "laptop"},
            {"column": "status", "operator": "in", "value": ["active", "featured"]}
        ],
        "sort_by": "price",
        "sort_order": "ASC",
        "limit": 20,
        "offset": 0,
        "include_count": true
    }
    """
    # Handle CORS preflight
    if request.method == "OPTIONS":
        headers = {
            "Access-Control-Allow-Origin": "*",
            "Access-Control-Allow-Methods": "POST, GET",
            "Access-Control-Allow-Headers": "Content-Type, Authorization",
            "Access-Control-Max-Age": "3600",
        }
        return ("", 204, headers)

    response_headers = {
        "Access-Control-Allow-Origin": "*",
        "Content-Type": "application/json",
    }

    try:
        # Parse request
        if request.method == "GET":
            # Support GET with query parameters for simple searches
            request_data = {
                "table": request.args.get("table"),
                "fields": request.args.get("fields", "").split(",") if request.args.get("fields") else None,
                "sort_by": request.args.get("sort_by"),
                "sort_order": request.args.get("sort_order", "ASC"),
                "limit": int(request.args.get("limit", DEFAULT_LIMIT)),
                "offset": int(request.args.get("offset", 0)),
                "include_count": request.args.get("include_count", "false").lower() == "true",
            }
            # Parse simple filters from query params: filter_column=operator:value
            filters = []
            for key, value in request.args.items():
                if key.startswith("filter_"):
                    column = key[len("filter_"):]
                    if ":" in value:
                        operator, val = value.split(":", 1)
                        # Handle 'in' operator values as comma-separated
                        if operator == "in":
                            val = [v.strip() for v in val.split(",")]
                        filters.append({"column": column, "operator": operator, "value": val})
                    else:
                        filters.append({"column": column, "operator": "eq", "value": value})
            if filters:
                request_data["filters"] = filters
        else:
            request_data = request.get_json(silent=True)
            if not request_data:
                return (
                    json.dumps({"error": "Request body must be valid JSON"}),
                    400,
                    response_headers,
                )

        # Validate required fields
        table = request_data.get("table")
        if not table:
            return (
                json.dumps({
                    "error": "Missing required field: 'table'",
                    "available_tables": list(ALLOWED_TABLES.keys()),
                }),
                400,
                response_headers,
            )

        filters = request_data.get("filters", [])
        fields = request_data.get("fields")
        sort_by = request_data.get("sort_by")
        sort_order = request_data.get("sort_order", "ASC")
        limit = request_data.get("limit", DEFAULT_LIMIT)
        offset = request_data.get("offset", 0)
        include_count = request_data.get("include_count", False)

        # Build parameterized query
        query, params = build_dynamic_query(
            table=table,
            filters=filters,
            fields=fields,
            sort_by=sort_by,
            sort_order=sort_order,
            limit=limit,
            offset=offset,
        )

        # Execute query
        connection = get_connection()
        try:
            with connection.cursor() as cursor:
                cursor.execute(query, params)
                results = cursor.fetchall()

                # Convert any non-serializable types
                for row in results:
                    for key, value in row.items():
                        if hasattr(value, "isoformat"):
                            row[key] = value.isoformat()
                        elif isinstance(value, bytes):
                            row[key] = value.decode("utf-8", errors="replace")
                        elif isinstance(value, (int, float, str, bool, type(None))):
                            pass
                        else:
                            row[key] = str(value)

                total_count = None
                if include_count:
                    count_query, count_params = build_count_query(table, filters)
                    cursor.execute(count_query, count_params)
                    count_result = cursor.fetchone()
                    total_count = count_result["total"] if count_result else 0

        finally:
            connection.close()

        # Build response
        response_body = {
            "success": True,
            "table": table,
            "results": results,
            "result_count": len(results),
            "limit": min(int(limit), MAX_LIMIT),
            "offset": max(int(offset), 0),
        }

        if total_count is not None:
            response_body["total_count"] = total_count
            response_body["has_more"] = (max(int(offset), 0) + len(results)) < total_count

        return (json.dumps(response_body, default=str), 200, response_headers)

    except ValueError as e:
        return (
            json.dumps({"success": False, "error": f"Validation error: {str(e)}"}),
            400,
            response_headers,
        )
    except pymysql.OperationalError as e:
        error_code = e.args[0] if e.args else None
        return (
            json.dumps({
                "success": False,
                "error": "Database connection error",
                "detail": f"Error code: {error_code}",
            }),
            503,
            response_headers,
        )
    except pymysql.ProgrammingError as e:
        return (
            json.dumps({"success": False, "error": "Query error", "detail": str(e)}),
            400,
            response_headers,
        )
    except Exception as e:
        # Log the full error server-side but don't expose internals
        print(f"Unexpected error: {type(e).__name__}: {e}")
        return (
            json.dumps({"success": False, "error": "Internal server error"}),
            500,
            response_headers,
        )


def get_schema(request):
    """
    Helper endpoint to return available tables, columns, and operators.
    Useful for clients building dynamic search UIs.
    """
    response_headers = {
        "Access-Control-Allow-Origin": "*",
        "Content-Type": "application/json",
    }

    schema = {}
    for table, config in ALLOWED_TABLES.items():
        schema[table] = {
            "columns": sorted(config["columns"]),
            "searchable_columns": sorted(config["searchable"]),
            "sortable_columns": sorted(config["sortable"]),
        }

    return (
        json.dumps({
            "tables": schema,
            "operators": {k: v for k, v in ALLOWED_OPERATORS.items()},
            "max_limit": MAX_LIMIT,
            "default_limit": DEFAULT_LIMIT,
        }),
        200,
        response_headers,
    )